37	function missingRuntimeMessage(report: AiRuntimeReport): string {
38	  if (report.preference === "standalone-only") {
39	    return [
40	      "Keating is configured for standalone-only but no `pi` AI agent binary was found on PATH.",
41	      "",
42	      "Recover with one of:",
43	      "  npm install -g @earendil-works/pi-coding-agent",
44	      "  keating setup",
45	      "  edit keating.config.json and set pi.runtimePreference to prefer-standalone"
46	    ].join("\n");
47	  }
48	
49	  if (report.preference === "embedded-only") {
50	    return [
51	      "Keating is configured for embedded-only but no embedded AI agent was found.",
52	      "",
53	      "Recover with one of:",
54	      "  npm install -g @earendil-works/pi-coding-agent",
55	      "  keating setup",
56	      "  npm install -g keating"
57	    ].join("\n");
58	  }
59	
60	  return [
61	    "Could not find an AI runtime.",
62	    "",
63	    "Recover with one of:",
64	    "  npm install -g @earendil-works/pi-coding-agent",
65	    "  npm install -g keating",
66	    "  curl -fsSL https://raw.githubusercontent.com/Diogenesoftoronto/keating/main/scripts/install/install.sh | bash"
67	  ].join("\n");
68	}
69	
70	function resolveStandaloneAgent(): AiRuntimeDetails | null {
71	  const result = spawnSync("which", ["pi"], { encoding: "utf8", env: process.env });
72	  if (result.status === 0 && result.stdout.trim()) {
73	    const command = result.stdout.trim();
74	    const versionResult = spawnSync(command, ["--version"], { encoding: "utf8", env: process.env });
75	    if (versionResult.status === 0 && /^\d+\.\d+\.\d+/.test(versionResult.stdout.trim())) {
76	      return {
77	        kind: "binary",
78	        command
79	      };
80	    }
81	  }
82	  return null;
83	}
