91	async function syncPiSettings(cwd: string, config: KeatingConfig): Promise<void> {
92	  const agentDir = configDir(cwd);
93	  const settingsPath = join(agentDir, "settings.json");
94	  let settings: Record<string, unknown> = {};
95	
96	  try {
97	    const parsed = JSON.parse(await readFile(settingsPath, "utf8"));
98	    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
99	      settings = parsed as Record<string, unknown>;
100	    }
101	  } catch {
102	    settings = {};
103	  }
104	
105	  const quietStartup = !config.debug.consoleSummary;
106	  if (settings.quietStartup === quietStartup) return;
