1	import { getModels, getProviders, type Api, type Model } from "@earendil-works/pi-ai";
2	import { getAppStorage, type CustomProvider } from "@earendil-works/pi-web-ui";
3	import { proxiedProviderRequestUrl } from "./provider-proxy";
4	import { getOAuthAccessToken, providerToOAuthId } from "../keating/oauth";
5	import { withApiRetry } from "../keating/api-retry";
6	
7	export type KeatingCustomProviderType =
8		| "ollama"
9		| "llama.cpp"
10		| "vllm"
11		| "lmstudio"
12		| "openai-completions"
13		| "openai-responses"
14		| "anthropic-messages"
15		| "synthetic";
16	
17	export type KeatingCustomProvider = Omit<CustomProvider, "type"> & {
18		type: KeatingCustomProviderType;
19	};
20	
21	const AUTO_DISCOVERY_TYPES = new Set<KeatingCustomProviderType>(["ollama", "llama.cpp", "vllm", "lmstudio"]);
22	const OPENAI_COMPATIBLE_TYPES = new Set<KeatingCustomProviderType>([
23		"openai-completions",
24		"openai-responses",
25		"synthetic",
26	]);
27	
28	function trimTrailingSlash(value: string): string {
29		return value.replace(/\/+$/, "");
30	}
31	
32	function modelCost() {
33		return {
34			input: 0,
35			output: 0,
36			cacheRead: 0,
37			cacheWrite: 0,
38		};
39	}
40	
41	function toContextWindow(value: unknown, fallback = 0): number {
42		if (typeof value === "number" && Number.isFinite(value)) return value;
43		if (typeof value === "string") {
44			const parsed = Number.parseInt(value, 10);
45			if (Number.isFinite(parsed)) return parsed;
46		}
47		return fallback;
48	}
49	
50	function inferInputModes(model: any): Array<"text" | "image"> {
51		const supported = new Set<string>();
52	
53		if (Array.isArray(model?.input)) {
54			for (const entry of model.input) {
55				if (entry === "image" || entry === "text") supported.add(entry);
56			}
57		}
58	
59		if (Array.isArray(model?.input_modalities)) {
60			for (const entry of model.input_modalities) {
61				if (entry === "image" || entry === "text") supported.add(entry);
62			}
63		}
64	
65		if (Array.isArray(model?.modalities)) {
66			for (const entry of model.modalities) {
67				if (entry === "image" || entry === "text") supported.add(entry);
68			}
69		}
70	
71		if (model?.vision === true) supported.add("image");
72		if (supported.size === 0) supported.add("text");
73	
74		return Array.from(supported) as Array<"text" | "image">;
75	}
76	
77	function inferReasoning(model: any): boolean {
78		if (typeof model?.reasoning === "boolean") return model.reasoning;
79		if (typeof model?.supports_reasoning === "boolean") return model.supports_reasoning;
80		if (Array.isArray(model?.capabilities)) return model.capabilities.includes("thinking");
81		const name = String(model?.id ?? model?.name ?? "").toLowerCase();
82		return name.includes("thinking") || name.includes("reasoning");
83	}
84	
85	function manualProviderApi(type: KeatingCustomProviderType): Api {
86		switch (type) {
87			case "openai-responses":
88				return "openai-responses" as Api;
89			case "anthropic-messages":
90				return "anthropic-messages" as Api;
91			case "synthetic":
92			case "openai-completions":
93			default:
94				return "openai-completions" as Api;
95		}
96	}
97	
98	async function fetchJson(url: string, apiKey?: string, options: { method?: "GET" | "POST"; body?: unknown } = {}): Promise<any> {
99		const proxied = proxiedProviderRequestUrl(url);
100		const headers: Record<string, string> = {
101			"x-target-url": proxied.targetBaseUrl,
102		};
103	
104		if (options.body !== undefined) headers["Content-Type"] = "application/json";
105		if (apiKey) {
106			headers.Authorization = `Bearer ${apiKey}`;
107		}
108	
109		const response = await withApiRetry(async () => {
110			const result = await fetch(proxied.url, {
111				method: options.method ?? "GET",
112				headers,
113				body: options.body === undefined ? undefined : JSON.stringify(options.body),
114			});
115			if (!result.ok) {
116				const retryAfter = result.headers.get("retry-after");
117				throw new Error(`HTTP ${result.status}: ${result.statusText}${retryAfter ? ` retry-after: ${retryAfter}` : ""}`);
118			}
119			return result;
120		});
121	
122		return await response.json();
123	}
124	
125	async function discoverOpenAiCompatibleModels(
126		provider: KeatingCustomProvider,
127	): Promise<{ apiBaseUrl: string; models: Model<Api>[] }> {
128		const baseUrl = trimTrailingSlash(provider.baseUrl);
129		const candidateBaseUrls = baseUrl.endsWith("/v1") ? [baseUrl] : [baseUrl, `${baseUrl}/v1`];
130	
131		let lastError: unknown;
132		for (const apiBaseUrl of candidateBaseUrls) {
133			try {
134				const payload = await fetchJson(`${apiBaseUrl}/models`, provider.apiKey);
135				const records = Array.isArray(payload?.data) ? payload.data : Array.isArray(payload) ? payload : [];
136					const models = records
137						.map((record: any): Model<Api> | null => {
138						const id = String(record?.id ?? record?.name ?? "").trim();
139						if (!id) return null;
140	
141						const contextWindow = toContextWindow(
142							record?.context_window ?? record?.context_length ?? record?.max_context_length ?? record?.max_model_len,
143						);
144						const maxTokens = toContextWindow(record?.max_tokens ?? record?.max_output_tokens, contextWindow || 4096);
145	
146						return {
147							id,
148							name: String(record?.name ?? id),
149							api: manualProviderApi(provider.type),
150							provider: provider.name,
151							baseUrl: apiBaseUrl,
152							reasoning: inferReasoning(record),
153							input: inferInputModes(record),
154							cost: modelCost(),
155							contextWindow,
156							maxTokens,
157						};
158						})
159						.filter((model: Model<Api> | null): model is Model<Api> => model !== null);
160	
161				return { apiBaseUrl, models };
162			} catch (error) {
163				lastError = error;
164			}
165		}
166	
167		throw lastError instanceof Error ? lastError : new Error(`Failed to discover models for ${provider.name}`);
168	}
169	
170	async function discoverOllamaModels(baseUrl: string): Promise<Model<Api>[]> {
171		const trimmedBaseUrl = trimTrailingSlash(baseUrl);
172		const payload = await fetchJson(`${trimmedBaseUrl}/api/tags`);
173		const models = Array.isArray(payload?.models) ? payload.models : [];
174	
175		const discovered = await Promise.all(
176			models.map(async (model: any): Promise<Model<Api> | null> => {
177				const details = await fetchJson(`${trimmedBaseUrl}/api/show`, undefined, {
178					method: "POST",
179					body: { model: model.name },
180				});
181				const capabilities: string[] = (details as any).capabilities || [];
182				if (!capabilities.includes("tools")) return null;
183	
184				const modelInfo: any = details.model_info || {};
185				const architecture = modelInfo["general.architecture"] || "";
186				const contextWindow = toContextWindow(modelInfo[`${architecture}.context_length`], 8192);
187	
188				return {
189					id: model.name,
190					name: model.name,
191					api: "openai-completions" as Api,
192					provider: "",
193					baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
194					reasoning: capabilities.includes("thinking"),
195					input: ["text"],
196					cost: modelCost(),
197					contextWindow,
198					maxTokens: contextWindow,
199				};
200			}),
201		);
202	
203		return discovered.filter((model): model is Model<Api> => model !== null);
204	}
205	
206	async function discoverLlamaCppModels(baseUrl: string, apiKey?: string): Promise<Model<Api>[]> {
207		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`, apiKey);
208		const records = Array.isArray(payload?.data) ? payload.data : [];
209	
210		return records.map((model: any) => {
211			const contextWindow = toContextWindow(model?.context_length, 8192);
212			return {
213				id: String(model.id),
214				name: String(model.id),
215				api: "openai-completions" as Api,
216				provider: "",
217				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
218				reasoning: false,
219				input: ["text"],
220				cost: modelCost(),
221				contextWindow,
222				maxTokens: toContextWindow(model?.max_tokens, 4096),
223			};
224		});
225	}
226	
227	async function discoverVllmModels(baseUrl: string, apiKey?: string): Promise<Model<Api>[]> {
228		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`, apiKey);
229		const records = Array.isArray(payload?.data) ? payload.data : [];
230	
231		return records.map((model: any) => {
232			const contextWindow = toContextWindow(model?.max_model_len, 8192);
233			return {
234				id: String(model.id),
235				name: String(model.id),
236				api: "openai-completions" as Api,
237				provider: "",
238				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
239				reasoning: false,
240				input: ["text"],
241				cost: modelCost(),
242				contextWindow,
243				maxTokens: Math.min(contextWindow, 4096),
244			};
245		});
246	}
247	
248	async function discoverLmStudioModels(baseUrl: string): Promise<Model<Api>[]> {
249		const payload = await fetchJson(`${trimTrailingSlash(baseUrl)}/v1/models`);
250		const records = Array.isArray(payload?.data) ? payload.data : [];
251	
252		return records.map((model: any) => {
253			const contextWindow = toContextWindow(model?.context_length ?? model?.max_context_length, 8192);
254			return {
255				id: String(model?.id),
256				name: String(model?.name ?? model?.id),
257				api: "openai-completions" as Api,
258				provider: "",
259				baseUrl: `${trimTrailingSlash(baseUrl)}/v1`,
260				reasoning: inferReasoning(model),
261				input: inferInputModes(model),
262				cost: modelCost(),
263				contextWindow,
264				maxTokens: toContextWindow(model?.max_tokens, contextWindow),
265			};
266		});
267	}
268	
269	async function discoverCustomProviderModels(provider: KeatingCustomProvider): Promise<Model<Api>[]> {
270		if (AUTO_DISCOVERY_TYPES.has(provider.type)) {
271			let models: Model<Api>[];
272			switch (provider.type) {
273				case "ollama":
274					models = await discoverOllamaModels(provider.baseUrl);
275					break;
276				case "llama.cpp":
277					models = await discoverLlamaCppModels(provider.baseUrl, provider.apiKey);
278					break;
279				case "vllm":
280					models = await discoverVllmModels(provider.baseUrl, provider.apiKey);
281					break;
282				case "lmstudio":
283					models = await discoverLmStudioModels(provider.baseUrl);
284					break;
285				default:
286					models = [];
287			}
288	
289			return models.map((model) => ({ ...model, provider: provider.name }));
290		}
291	
292		if (OPENAI_COMPATIBLE_TYPES.has(provider.type)) {
293			const discovered = await discoverOpenAiCompatibleModels(provider);
294			return discovered.models;
295		}
296	
297		return (provider.models || []).map((model) => ({
298			...model,
299			provider: provider.name,
300			baseUrl: model.baseUrl || provider.baseUrl,
301			api: model.api || manualProviderApi(provider.type),
302		}));
303	}
304	
305	export async function getCustomProviders(): Promise<KeatingCustomProvider[]> {
306		return (await getAppStorage().customProviders.getAll()) as KeatingCustomProvider[];
307	}
308	
309	export async function syncCustomProviderKeys(): Promise<void> {
310		const storage = getAppStorage();
311		const providers = await getCustomProviders();
312	
313		await Promise.all(
314			providers.map(async (provider) => {
315				if (provider.apiKey) {
316					await storage.providerKeys.set(provider.name, provider.apiKey);
317				}
318			}),
319		);
320	}
321	
322	export async function getProviderApiKey(providerName: string): Promise<string | undefined> {
323		const oauthId = providerToOAuthId(providerName);
324		if (oauthId) {
325			const token = await getOAuthAccessToken(oauthId);
326			if (token) return token;
327		}
328	
329		const storage = getAppStorage();
330		const storedKey = await storage.providerKeys.get(providerName);
331		if (storedKey) return storedKey;
332	
333		const customProviders = await getCustomProviders();
334		return customProviders.find((provider) => provider.name === providerName)?.apiKey;
335	}
336	
337	export const UNKNOWN_COST = {
338		input: 0,
339		output: 0,
340		cacheRead: 0,
341		cacheWrite: 0,
342	} as const;
343	
344	export const UNKNOWN_CONTEXT_WINDOW = 8192;
345	export const UNKNOWN_MAX_TOKENS = 4096;
346	
347	export async function getSelectableModels(
348		filter?: (provider: string) => boolean,
349	): Promise<Array<Model<Api>>> {
350		const models: Array<Model<Api>> = [];
351	
352		for (const provider of getProviders()) {
353			if (!filter || filter(provider)) {
354				models.push(...(getModels(provider as any) as Array<Model<Api>>));
355			}
356		}
357	
358		const customProviders = await getCustomProviders();
359		const customModels = await Promise.all(
360			customProviders.map(async (provider) => {
361				try {
362					return await discoverCustomProviderModels(provider);
363				} catch (error) {
364					console.warn(`Skipping unavailable provider ${provider.name}:`, error);
365					return [];
366				}
367			}),
368		);
369	
370		models.push(...customModels.flat());
371		return models;
372	}
373	
374	export function buildSavedModel(saved: any): Model<Api> {
375		return {
376			id: saved.id,
377			name: saved.name,
378			api: saved.api as Api,
379			provider: saved.provider,
380			baseUrl: saved.baseUrl || "",
381			reasoning: saved.reasoning,
382			input: saved.vision ? (["text", "image"] as Array<"text" | "image">) : (["text"] as Array<"text" | "image">),
383			cost: UNKNOWN_COST,
384			contextWindow: UNKNOWN_CONTEXT_WINDOW,
385			maxTokens: UNKNOWN_MAX_TOKENS,
386		};
387	}
