578	function OAuthProviderKeys({ providers }: { providers: string[] }) {
579		const [keys, setKeys] = useState<Record<string, string>>({});
580		const [oauthStatus, setOAuthStatus] = useState<Record<string, boolean>>({});
581		const [oauthLoading, setOauthLoading] = useState<Record<string, boolean>>({});
582		const [oauthInputs, setOAuthInputs] = useState<Record<string, string>>({});
583		const [oauthErrors, setOAuthErrors] = useState<Record<string, string>>({});
584	
585		useEffect(() => {
586			const storage = getAppStorage();
587			Promise.all(providers.map(async (p) => ({
588				provider: p,
589				key: (await storage.providerKeys.get(p)) ?? "",
590			}))).then((results) => {
591				const map: Record<string, string> = {};
592				for (const { provider, key } of results) map[provider] = key;
593				setKeys(map);
594			});
595		}, [providers.join(",")]);
596	
597		useEffect(() => {
598			const checkOAuth = async () => {
599				const status: Record<string, boolean> = {};
600				for (const provider of providers) {
601					const oauthId = providerToOAuthId(provider);
602					if (oauthId) {
603						const creds = await loadOAuthCredentials(oauthId);
604						status[provider] = !!creds;
605					}
606				}
607				setOAuthStatus(status);
608			};
609			checkOAuth();
610		}, [providers.join(",")]);
611	
612		useEffect(() => {
613			const handler = (event: MessageEvent) => {
614				if (event.data?.type !== "keating-oauth-result") return;
615				const { success, provider: oauthProvider } = event.data;
616				const provider = oauthProviderToProviderName(oauthProvider);
617				if (success && oauthProvider) {
618					setOAuthStatus((prev) => ({ ...prev, [provider]: true }));
619					setOAuthInputs((prev) => ({ ...prev, [provider]: "" }));
620					setOAuthErrors((prev) => ({ ...prev, [provider]: "" }));
621				} else if (provider) {
622					setOAuthErrors((prev) => ({ ...prev, [provider]: event.data.error ?? "OAuth sign-in failed." }));
623				}
624				setOauthLoading((prev) => {
625					const next = { ...prev };
626					for (const k of Object.keys(next)) next[k] = false;
627					return next;
628				});
629			};
630			window.addEventListener("message", handler);
631			return () => window.removeEventListener("message", handler);
632		}, []);
633	
634		const save = async (provider: string, value: string) => {
635			const storage = getAppStorage();
636			if (value.trim()) {
637				await storage.providerKeys.set(provider, value.trim());
638			} else {
639				await storage.providerKeys.delete(provider);
640			}
641		};
642	
643		const handleSignIn = (provider: string) => {
644			const oauthId = providerToOAuthId(provider);
645			if (!oauthId) return;
646			setOAuthErrors((prev) => ({ ...prev, [provider]: "" }));
647			setOAuthInputs((prev) => ({ ...prev, [provider]: "" }));
648			setOauthLoading((prev) => ({ ...prev, [provider]: true }));
649			initiateOAuth(oauthId);
650		};
651	
652		const handleCompleteOAuth = async (provider: string) => {
653			const input = oauthInputs[provider]?.trim() ?? "";
654			if (!input) {
655				setOAuthErrors((prev) => ({ ...prev, [provider]: "Paste the callback URL or authorization code first." }));
656				return;
657			}
658			setOauthLoading((prev) => ({ ...prev, [provider]: true }));
659			setOAuthErrors((prev) => ({ ...prev, [provider]: "" }));
660			const result = await completeOAuthFromInput(input);
661			if (result.success && result.provider) {
662				const statusProvider = oauthProviderToProviderName(result.provider);
663				setOAuthStatus((prev) => ({ ...prev, [statusProvider]: true }));
664				setOAuthInputs((prev) => ({ ...prev, [provider]: "" }));
665			} else {
666				setOAuthErrors((prev) => ({ ...prev, [provider]: result.error ?? "OAuth sign-in failed." }));
667			}
668			setOauthLoading((prev) => ({ ...prev, [provider]: false }));
669		};
670	
671		const handleSignOut = async (provider: string) => {
672			const oauthId = providerToOAuthId(provider);
673			if (!oauthId) return;
674			await deleteOAuthCredentials(oauthId);
675			const storage = getAppStorage();
676			await storage.providerKeys.delete(provider);
677			setOAuthStatus((prev) => ({ ...prev, [provider]: false }));
678			setKeys((prev) => ({ ...prev, [provider]: "" }));
679		};
680	
681		const OAUTH_PROVIDER_LABELS: Record<string, string> = {
682			anthropic: "Anthropic",
683			"openai-codex": "OpenAI Codex",
684			google: "Google Gemini",
685		};
686	
687		return (
688			<>
689				{providers.map((provider) => {
690					const oauthId = providerToOAuthId(provider);
691					const isOAuth = !!oauthId;
692					const hasOAuth = oauthStatus[provider] === true;
693					const loading = oauthLoading[provider] === true;
694	
695					if (isOAuth) {
696						return (
697							<div key={provider} className="flex flex-col gap-1">
698								<div className="flex items-center justify-between gap-3">
699									<label className="text-xs font-medium text-muted-foreground capitalize">
700										{OAUTH_PROVIDER_LABELS[provider] ?? provider}
701									</label>
702									<a
703										href={tutorialApiKeyHref(provider)}
704										target="_blank"
705										rel="noreferrer"
706										className="text-xs text-primary underline underline-offset-2"
707									>
708										Get a key
709									</a>
710								</div>
711								{hasOAuth ? (
712									<div className="flex items-center justify-between gap-3 rounded-md border border-border bg-muted/30 px-3 py-2">
713										<span className="text-sm text-muted-foreground">Signed in</span>
714										<button
715											className="text-xs text-muted-foreground hover:text-foreground underline underline-offset-2"
716											onClick={() => handleSignOut(provider)}
717										>
718											Sign out
719										</button>
720									</div>
721								) : (
722									<div className="flex flex-col gap-2">
723										<button
724											className="inline-flex items-center justify-center rounded-md bg-primary px-3 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50"
725											disabled={loading}
726											onClick={() => handleSignIn(provider)}
727										>
728											{loading ? "Waiting for sign-in…" : `Sign in with ${OAUTH_PROVIDER_LABELS[provider] ?? provider}`}
729										</button>
730										{loading && (
731											<div className="rounded-md border border-border bg-muted/20 p-2">
732												<p className="mb-2 text-xs text-muted-foreground">
733													If the provider redirects to a localhost callback that does not load, paste that final URL here.
734												</p>
735												<div className="flex gap-2">
736													<input
737														type="text"
738														className="min-w-0 flex-1 rounded-md border border-border bg-background px-2 py-1.5 text-xs"
739														placeholder="Callback URL or authorization code"
740														value={oauthInputs[provider] ?? ""}
741														onChange={(e) => setOAuthInputs((prev) => ({ ...prev, [provider]: e.target.value }))}
742													/>
743													<button
744														className="rounded-md border border-border px-2 py-1.5 text-xs font-medium hover:bg-accent hover:text-accent-foreground transition-colors disabled:opacity-50"
745														disabled={!oauthInputs[provider]?.trim()}
746														onClick={() => handleCompleteOAuth(provider)}
747													>
748														Complete
749													</button>
750												</div>
751											</div>
752										)}
753										{oauthErrors[provider] && (
754											<div className="rounded-md border border-destructive/30 bg-destructive/5 px-3 py-2 text-xs text-destructive">
755												{oauthErrors[provider]}
756											</div>
757										)}
758									</div>
759								)}
760							</div>
761						);
762					}
763	
764					return (
765						<div key={provider} className="flex flex-col gap-1">
766							<div className="flex items-center justify-between gap-3">
767								<label className="text-xs font-medium text-muted-foreground capitalize">{provider} API Key</label>
768								<a
769									href={tutorialApiKeyHref(provider)}
770									target="_blank"
771									rel="noreferrer"
772									className="text-xs text-primary underline underline-offset-2"
773								>
774									Get a key
775								</a>
776							</div>
777							<input
778								type="password"
779								className="rounded-md border border-border bg-background px-3 py-2 text-sm"
780								placeholder={`${provider} API key`}
781								value={keys[provider] ?? ""}
782								onChange={(e) => setKeys((prev) => ({ ...prev, [provider]: e.target.value }))}
783								onBlur={(e) => save(provider, e.target.value)}
784							/>
785						</div>
786					);
787				})}
788			</>
789		);
790	}
