811				<div className="flex items-start justify-between gap-3">
812					<div className="min-w-0">
813						<div className="text-sm font-medium text-foreground">{provider.name}</div>
814						<div className="text-xs text-muted-foreground mt-0.5">{provider.type} — {provider.baseUrl}</div>
815						<div className="flex gap-2 mt-1">
816							<span className="inline-flex items-center rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
817								{isAutoDiscovery ? "Auto-discovery" : "Manual"}
818							</span>
819							<span className="inline-flex items-center rounded-full bg-muted px-2 py-0.5 text-[10px] font-medium text-muted-foreground">
820								{provider.models?.length ?? 0} models
821							</span>
822						</div>
823					</div>
824					<div className="flex items-center gap-1 shrink-0">
825						<button
826							className="inline-flex h-7 w-7 items-center justify-center rounded-md text-muted-foreground hover:bg-accent hover:text-accent-foreground"
827							onClick={onEdit}
828							aria-label="Edit provider"
829						>
830							<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
831						</button>
832						<button
833							className="inline-flex h-7 w-7 items-center justify-center rounded-md text-destructive hover:bg-destructive/10"
